    if (window.monetag && window.monetag.showInterstitial) {
      window.monetag.showInterstitial(() => {
        callback();
      });
      return;
    }

    // Fallback: Alert user to watch ad
    setTimeout(() => {
      alert('Ad opened in new tab. Click OK to start your call!');
